14	//
15	// Author: Brad Hyslop <bhyslop@scaleinvariant.org>
16	//
17	// RBTDRF — fast-tier test cases for theurge
18	//
19	// Ports enrollment-validation (47), regime-validation (21), and regime-smoke (7)
20	// from bash test framework to theurge. Cases shell out to bash — theurge invokes
21	// the actual bash utilities and asserts on exit codes. No reimplementation.
22	
23	use std::path::Path;
24	use std::process::Command;
25	
26	use crate::case;
27	use crate::rbtdre_engine::{rbtdre_Case, rbtdre_Disposition, rbtdre_Fixture, rbtdre_Verdict};
28	use crate::rbtdri_invocation::{rbtdri_find_tabtarget_global, rbtdri_tabtarget_command, rbtdri_bash_program};
29	use crate::rbtdgc_consts::{
30	    RBTDGC_BAND_CREDLESS,
31	    RBTDGC_HYGIENE_CHECK_DOCKERFILE,
32	    RBTDGC_HYGIENE_CHECK_VESSEL,
33	    RBTDGC_JETTISON_IMAGE,
34	    RBTDGC_LIST_DEPOT,
35	    RBTDGC_PRESAGE_IMMURE,
36	    RBTDGC_RBRS_FILE,
37	    RBTDGC_RENDER_NAMEPLATE,
38	    RBTDGC_RENDER_PAYOR,
39	    RBTDGC_RENDER_REPO,
40	    RBTDGC_RENDER_STATION,
41	    RBTDGC_RENDER_VESSEL,
42	    RBTDGC_UNMAKE_DEPOT,
43	    RBTDGC_VALIDATE_NAMEPLATE,
44	    RBTDGC_VALIDATE_PAYOR,
45	    RBTDGC_VALIDATE_REPO,
46	    RBTDGC_VALIDATE_STATION,
47	    RBTDGC_VALIDATE_VESSEL,
48	};
49	use crate::rbtdrm_manifest::{
50	    RBTDRM_FIXTURE_DOCKERFILE_HYGIENE,
51	    RBTDRM_FIXTURE_ENROLLMENT_VALIDATION,
52	    RBTDRM_FIXTURE_FOUNDRY_PATH,
53	    RBTDRM_FIXTURE_PODVM_RESOLVE,
54	    RBTDRM_FIXTURE_RECIPE_VALIDATION,
55	    RBTDRM_FIXTURE_REGIME_SMOKE,
56	    RBTDRM_FIXTURE_REGIME_VALIDATION,
57	    RBTDRM_MODULE_BURC,
58	    RBTDRM_MODULE_BURN,
59	    RBTDRM_MODULE_BURP,
60	    RBTDRM_MODULE_BURS,
61	    RBTDRM_MODULE_RBRA,
62	    RBTDRM_MODULE_RBRD,
63	    RBTDRM_MODULE_RBRN,
64	    RBTDRM_MODULE_RBRO,
65	    RBTDRM_MODULE_RBRP,
66	    RBTDRM_MODULE_RBRR,
67	    RBTDRM_MODULE_RBRS,
68	    RBTDRM_MODULE_RBRV,
69	    RBTDRM_PROBATE_BURC,
70	    RBTDRM_PROBATE_BURN,
71	    RBTDRM_PROBATE_BURP,
72	    RBTDRM_PROBATE_BURS,
73	    RBTDRM_PROBATE_RBRA,
74	    RBTDRM_PROBATE_RBRD,
75	    RBTDRM_PROBATE_RBRN,
76	    RBTDRM_PROBATE_RBRO,
77	    RBTDRM_PROBATE_RBRP,
78	    RBTDRM_PROBATE_RBRR,
79	    RBTDRM_PROBATE_RBRS,
80	    RBTDRM_PROBATE_RBRV,
81	};
82	use crate::rbtdrx_platform::rbtdrx_native_to_posix;
83	
84	// Repo-root-relative kit paths. Every probate harness runs with cwd = repo
85	// root, so these are repo-root-relative. Hoisted per RCG Identity Rule (cf.
86	// VVCC_REGISTRY_PATH) so running-code joins reference a named const rather
87	// than an inline magic string.
88	const RBTDRF_BUK_ROOT: &str = "Tools/buk";
89	const RBTDRF_RBK_ROOT: &str = "Tools/rbk";
90	const RBTDRF_BUV_VALIDATION: &str = "Tools/buk/buv_validation.sh";
91	const RBTDRF_BUC_COMMAND: &str = "Tools/buk/buc_command.sh";
92	const RBTDRF_RBLDS_SPINE: &str = "Tools/rbk/rblds_spine.sh";
93	
94	// ── Helpers ──────────────────────────────────────────────────
95	
96	/// Sub-assertion within a case: run bash snippet, check exit code.
97	struct RbtdrfSub {
98	    label: &'static str,
99	    setup: &'static str,
100	    command: &'static str,
101	    expect_ok: bool,
102	}
103	
104	impl RbtdrfSub {
105	    const fn ok(label: &'static str, setup: &'static str) -> Self {
106	        Self { label, setup, command: "buv_vet \"TEST\"", expect_ok: true }
107	    }
108	    const fn fatal(label: &'static str, setup: &'static str) -> Self {
109	        Self { label, setup, command: "buv_vet \"TEST\"", expect_ok: false }
110	    }
111	    const fn ok_cmd(label: &'static str, setup: &'static str, command: &'static str) -> Self {
112	        Self { label, setup, command, expect_ok: true }
113	    }
114	    const fn fatal_cmd(label: &'static str, setup: &'static str, command: &'static str) -> Self {
115	        Self { label, setup, command, expect_ok: false }
116	    }
117	}
118	
119	/// Run a bash script, return (exit_code, stdout, stderr). Saves traces to case dir.
120	fn rbtdrf_run_bash(
121	    project_root: &Path,
122	    script: &str,
123	    dir: &Path,
124	    trace_prefix: &str,
125	) -> Result<(i32, String, String), String> {
126	    let output = Command::new(rbtdri_bash_program())
127	        .arg("-c")
128	        .arg(script)
129	        .current_dir(project_root)
130	        .output()
131	        .map_err(|e| format!("bash execution failed: {}", e))?;
132	
133	    let stdout = String::from_utf8_lossy(&output.stdout).into_owned();
134	    let stderr = String::from_utf8_lossy(&output.stderr).into_owned();
135	    let code = output.status.code().unwrap_or(-1);
136	
137	    let _ = std::fs::write(dir.join(format!("{}-script.sh", trace_prefix)), script);
138	    let _ = std::fs::write(dir.join(format!("{}-stdout.txt", trace_prefix)), &stdout);
139	    let _ = std::fs::write(dir.join(format!("{}-stderr.txt", trace_prefix)), &stderr);
140	
141	    Ok((code, stdout, stderr))
142	}
143	
144	/// Run enrollment-validation sub-assertions against BUV.
145	fn rbtdrf_run_ev(
146	    dir: &Path,
147	    enrollment: &str,
148	    subs: &[RbtdrfSub],
149	) -> rbtdre_Verdict {
150	    let root = match std::env::current_dir() {
151	        Ok(r) => r,
152	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
153	    };
154	    let buv = root.join(RBTDRF_BUV_VALIDATION);
155	
156	    for (i, sub) in subs.iter().enumerate() {
157	        let script = format!(
158	            "set -euo pipefail\nsource '{}'\nzbuv_kindle\nzbuv_reset_enrollment\n{}\n{}\n{}",
159	            rbtdrx_native_to_posix(&buv),
160	            enrollment,
161	            sub.setup,
162	            sub.command,
163	        );
164	
165	        match rbtdrf_run_bash(&root, &script, dir, &format!("sub-{}", i)) {
166	            Ok((code, _, _)) => {
167	                let ok = code == 0;
168	                if ok != sub.expect_ok {
169	                    return if sub.expect_ok {
170	                        rbtdre_Verdict::Fail(format!("{}: expected ok, got exit {}", sub.label, code))
171	                    } else {
172	                        rbtdre_Verdict::Fail(format!("{}: expected failure, got exit 0", sub.label))
173	                    };
174	                }
175	            }
176	            Err(e) => {
177	                return rbtdre_Verdict::Fail(format!("{}: {}", sub.label, e));
178	            }
179	        }
180	    }
181	    rbtdre_Verdict::Pass
182	}
183	
184	/// Drive a regime's public `*_probate` function against a synthetic
185	/// baseline+override written to the case temp dir. `expect_ok` selects the
186	/// verdict polarity: pass-anchors validate the pristine baseline (true);
187	/// negatives apply one violating override and expect non-zero (false).
188	/// Sources only the contract surface — `buv_validation.sh` plus the one regime
189	/// module — mirroring the `buv_vet` bridge that enrollment-validation uses: no
190	/// internal-module chain, no z-private reach.
191	///
192	/// `tools_subdir` is the repo-relative directory holding the module
193	/// ("Tools/rbk" or "Tools/buk"). `prelude` is raw bash staged after buv's
194	/// kindle but before the regime module's probate — for regimes whose kindle or
195	/// enforce reaches a neighbor (rbrp → rbgc's payor regex; burs → bubc, whose
196	/// constants its enrollment help-string expands). Relative paths resolve
197	/// against cwd (the repo root, set by rbtdrf_run_bash). Empty for the common
198	/// case, mirroring how rbtdrf_rs_rbrr_nonempty_prefix stages rbgc in-harness.
199	fn rbtdrf_run_probate_in(
200	    dir: &Path,
201	    tools_subdir: &str,
202	    module: &str,
203	    probate_fn: &str,
204	    prelude: &str,
205	    baseline: &str,
206	    override_: &str,
207	    expect_ok: bool,
208	    label: &str,
209	) -> rbtdre_Verdict {
210	    let root = match std::env::current_dir() {
211	        Ok(r) => r,
212	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
213	    };
214	    let buv = root.join(RBTDRF_BUV_VALIDATION);
215	    let module_path = root.join(tools_subdir).join(module);
216	
217	    let env_file = dir.join(format!("{}.env", label));
218	    let body = format!("{}\n{}\n", baseline, override_);
219	    if let Err(e) = std::fs::write(&env_file, &body) {
220	        return rbtdre_Verdict::Fail(format!("{}: write env failed: {}", label, e));
221	    }
222	
223	    let script = format!(
224	        "set -euo pipefail\n\
225	         source '{}'\n\
226	         source '{}'\n\
227	         zbuv_kindle\n\
228	         {}\
229	         {} '{}'",
230	        rbtdrx_native_to_posix(&buv),
231	        rbtdrx_native_to_posix(&module_path),
232	        prelude,
233	        probate_fn,
234	        rbtdrx_native_to_posix(&env_file),
235	    );
236	
237	    match rbtdrf_run_bash(&root, &script, dir, label) {
238	        Ok((code, _, _)) => {
239	            let ok = code == 0;
240	            if ok == expect_ok {
241	                rbtdre_Verdict::Pass
242	            } else if expect_ok {
243	                rbtdre_Verdict::Fail(format!("{}: expected ok, got exit {}", label, code))
244	            } else {
245	                rbtdre_Verdict::Fail(format!("{}: expected failure, got exit 0", label))
246	            }
247	        }
248	        Err(e) => rbtdre_Verdict::Fail(format!("{}: {}", label, e)),
249	    }
250	}
251	
252	/// Common-case wrapper: RBK module, no prereqs. Preserves the call shape used
253	/// by the reference rv_ quartet (rbrr/rbrd/rbrv/rbrn).
254	fn rbtdrf_run_probate(
255	    dir: &Path,
256	    module: &str,
257	    probate_fn: &str,
258	    baseline: &str,
259	    override_: &str,
260	    expect_ok: bool,
