1303	fn rbtdrf_rv_rbrr_repo(dir: &Path) -> rbtdre_Verdict {
1304	    let root = match std::env::current_dir() {
1305	        Ok(r) => r,
1306	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
1307	    };
1308	    match rbtdrf_run_tt(&root, RBTDGC_VALIDATE_REPO, &[], dir, "rbrr-repo-validate") {
1309	        Ok(()) => rbtdre_Verdict::Pass,
1310	        Err(e) => rbtdre_Verdict::Fail(e),
1311	    }
