1314	fn rbtdrf_rv_rbrv_all_vessels(dir: &Path) -> rbtdre_Verdict {
1315	    let root = match std::env::current_dir() {
1316	        Ok(r) => r,
1317	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
1318	    };
1319	
1320	    // Discover vessels: source rbrr.env to get RBRR_VESSEL_DIR, scan it
1321	    let buv = root.join(RBTDRF_BUV_VALIDATION);
1322	    let rbk = root.join(RBTDRF_RBK_ROOT);
1323	    let buv_p = rbtdrx_native_to_posix(&buv);
1324	    let rbk_p = rbtdrx_native_to_posix(&rbk);
1325	    let script = format!(
1326	        "set -euo pipefail\n\
1327	         source '{}'\n\
1328	         source '{}/rbcc_constants.sh'\n\
1329	         source '{}/rbgc_constants.sh'\n\
1330	         source '{}/rbrr_regime.sh'\n\
1331	         source '{}/rbrd_regime.sh'\n\
1332	         source '{}/rbdc_derived.sh'\n\
1333	         zbuv_kindle\nzrbcc_kindle\n\
1334	         source \"${{PWD}}/{moorings}/rbrr.env\"\n\
1335	         source \"${{PWD}}/{moorings}/rbrd.env\"\n\
1336	         zrbrr_kindle\nzrbrd_kindle\nzrbrr_enforce\nzrbrd_enforce\nzrbdc_kindle\n\
1337	         echo \"${{RBRR_VESSEL_DIR}}\"",
1338	        buv_p,
1339	        rbk_p, rbk_p, rbk_p, rbk_p, rbk_p,
1340	        moorings = crate::rbtdgc_consts::RBTDGC_MOORINGS_DIR,
1341	    );
1342	
1343	    let vessel_dir = match rbtdrf_run_bash(&root, &script, dir, "rbrv-discover") {
1344	        Ok((0, stdout, _)) => stdout.trim().to_string(),
1345	        Ok((code, _, _)) => {
1346	            return rbtdre_Verdict::Fail(format!("vessel discovery failed (exit {})", code));
1347	        }
1348	        Err(e) => return rbtdre_Verdict::Fail(e),
1349	    };

