    if let Err(e) = rbtdrf_run_tt(&root, render, &[], dir, &format!("{}-render", label)) {
        return rbtdre_Verdict::Fail(e);
    }
    if let Err(e) = rbtdrf_run_tt(&root, validate, &[], dir, &format!("{}-validate", label)) {
        return rbtdre_Verdict::Fail(e);
    }
    rbtdre_Verdict::Pass
}

